const event = $node["Split Events"].json;
const googleEvent = $node["Check if Event Exists in Google"].json;

// If Google event exists, update it; otherwise create it
const action = googleEvent.id ? 'update' : 'create';

return [{
  json: {
    action,
    supabaseEventId: event.id,
    googleEventId: googleEvent.id || null,
    summary: event.title,
    description: event.description,
    location: event.location,
    start: {
      dateTime: event.event_datetime,
      timeZone: 'UTC'
    },
    end: {
      dateTime: event.end_datetime || event.event_datetime,
      timeZone: 'UTC'
    }
  }
}];

const supabaseEvent = $node["Loop Over Items"].json;
const googleResponse = $input.first().json;

// Check if Google operation succeeded
const succeeded = googleResponse && googleResponse.id;

return [{
  json: {
    supabase_id: supabaseEvent.id,
    google_calendar_id: succeeded ? (googleResponse.organizer?.email || 'primary') : supabaseEvent.google_calendar_id,
    google_event_id: succeeded ? googleResponse.id : supabaseEvent.google_event_id,
    google_etag: succeeded ? googleResponse.etag : supabaseEvent.google_etag,
    remote_modified_at: succeeded ? googleResponse.updated : supabaseEvent.remote_modified_at,
    sync_status: succeeded ? 'synced' : 'error',
    last_synced_at: succeeded ? new Date().toISOString() : supabaseEvent.last_synced_at,
    sync_attempts: supabaseEvent.sync_attempts + 1,
    sync_error: succeeded ? null : 'Google Calendar API error',
    is_conflict: false
  }
}];
